import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { ValidationPipe } from '@nestjs/common';
import * as dotenv from 'dotenv';
import * as path from 'path';
import { IoAdapter } from '@nestjs/platform-socket.io';

// Load environment variables with absolute path resolution
dotenv.config({ path: path.resolve(__dirname, '../../.env') });

async function bootstrap() {
  // Validate critical environment variables
  if (!process.env.JWT_SECRET) {
    throw new Error('CRITICAL: JWT_SECRET environment variable must be set. Application cannot start without it.');
  }

  if (!process.env.DATABASE_URL) {
    throw new Error('CRITICAL: DATABASE_URL environment variable must be set. Application cannot start without it.');
  }

  const app = await NestFactory.create(AppModule, {
    logger: ['error', 'warn', 'log', 'debug', 'verbose'],
  });

  // Enable CORS with specific origin (security hardening)
  const allowedOrigins = process.env.FRONTEND_URL?.split(',') || ['http://localhost:3000'];
  app.enableCors({
    origin: allowedOrigins,
    credentials: true,
  });

  // Global Validation Pipe (NestJS Pattern from Universal Brain)
  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,              // Strip properties that don't have decorators
      forbidNonWhitelisted: true,   // Throw error if non-whitelisted properties exist
      transform: true,               // Auto-transform payloads to DTO instances
      transformOptions: {
        enableImplicitConversion: true,
      },
    })
  );

  // Set API base route
  app.setGlobalPrefix('api');

  // Configure global WebSockets connection adapter
  app.useWebSocketAdapter(new IoAdapter(app));

  const port = process.env.PORT || 8000;
  await app.listen(port);

  console.log(`\n======================================================`);
  console.log(`🚀 VULNX HUNTER CORE API RUNNING ON PORT: ${port}`);
  console.log(`🧪 ENDPOINTS STAGED AT: http://localhost:${port}/api`);
  console.log(`✅ Global Validation: ENABLED`);
  console.log(`✅ CORS Origins: ${allowedOrigins.join(', ')}`);
  console.log(`======================================================\n`);
}

bootstrap().catch((error) => {
  console.error('❌ Failed to start application:', error);
  process.exit(1);
});

